def test_enterprise_current_checkpoint_validates_immutable_packet(
    tmp_path: Path,
) -> None:
    commit = "a" * 40

    def write_packet(
        parent: Path,
        *,
        release_commit: str = commit,
        release_dirty: bool = False,
        release_returncodes: tuple[int, ...] = (0,),
        release_marker: bool = True,
        wrapper_returncode: int = 0,
        release_metadata_extra: tuple[str, ...] = (),
        release_trailing_output: tuple[str, ...] = (),
        release_check_override: str | None = None,
        git_summary_extra: tuple[str, ...] = (),
        nested_payload: bool = False,
    ) -> Path:
        packet = parent / f"ithildin-v0.2-review-packet-{commit[:12]}"
        packet.mkdir(parents=True)
        payload_path = "nested/payload.txt" if nested_payload else "payload.txt"
        pre_scan_artifacts = {
            "git-summary.txt": (
                f"commit={commit}\n"
                "branch=test\n"
                "dirty=false\n"
                + "".join(f"{line}\n" for line in git_summary_extra)
            ),
            "release-check.txt": (
                "$ make release-check\n"
                f"returncode={wrapper_returncode}\n\n"
                "## stdout\n"
                + ("$ make release-check\n" if release_marker else "")
                + "repo_root=/bounded/repository\n"
                f"git_commit={release_commit}\n"
                f"git_dirty={str(release_dirty).lower()}\n"
                + "".join(f"{line}\n" for line in release_metadata_extra)
                + "bounded release output\n"
                + "".join(
                    f"returncode={returncode}\n"
                    for returncode in release_returncodes
                )
                + "".join(f"{line}\n" for line in release_trailing_output)
                + "\n## stderr\n\n"
            )
            if release_check_override is None
            else release_check_override,
            payload_path: "bounded evidence\n",
        }
        artifacts = {
            **pre_scan_artifacts,
            "packet-redaction-scan.txt": (
                "# Ithildin Packet Redaction Scan\n\n"
                "roots: `1`\n"
                f"scanned_files: `{len(pre_scan_artifacts)}`\n"
                "findings: `0`\n\n"
                "Packet redaction scan passed.\n"
            ),
        }
        hashes: list[dict[str, object]] = []
        for relative, content in artifacts.items():
            encoded = content.encode()
            artifact = packet / relative
            artifact.parent.mkdir(parents=True, exist_ok=True)
            artifact.write_bytes(encoded)
            hashes.append(
                {
                    "bytes": len(encoded),
                    "path": relative,
                    "sha256": f"sha256:{hashlib.sha256(encoded).hexdigest()}",
                }
            )
        packet.joinpath("artifact-hashes.json").write_text(
            json.dumps(hashes),
            encoding="utf-8",
        )
        return packet

    generated_transcript = tmp_path / "generated-release-transcript.txt"
    generated_transcript.write_text(
        "$ make release-check\n"
        "repo_root=/bounded/repository\n"
        f"git_commit={commit}\n"
        "git_dirty=false\n"
        "bounded release output\n"
        "returncode=0\n",
        encoding="utf-8",
    )
    generated_release_check = tmp_path / "generated-release-check.txt"
    review_packet_bundle._write_command_output(
        generated_release_check,
        review_packet_bundle._load_release_check_transcript(generated_transcript),
    )
    valid_packet = write_packet(
        tmp_path / "valid",
        release_check_override=generated_release_check.read_text(encoding="utf-8"),
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(valid_packet, commit)
        is True
    )

    valid_packet.joinpath("payload.txt").write_text("tampered\n", encoding="utf-8")
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(valid_packet, commit)
        is False
    )

    cross_candidate = write_packet(
        tmp_path / "cross-candidate",
        release_commit="b" * 40,
        release_dirty=True,
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(
            cross_candidate,
            commit,
        )
        is False
    )

    markerless = write_packet(
        tmp_path / "markerless",
        release_marker=False,
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(
            markerless,
            commit,
        )
        is False
    )

    failed_then_successful = write_packet(
        tmp_path / "failed-then-successful",
        release_returncodes=(1, 0),
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(
            failed_then_successful,
            commit,
        )
        is False
    )

    failed_wrapper = write_packet(
        tmp_path / "failed-wrapper",
        wrapper_returncode=1,
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(
            failed_wrapper,
            commit,
        )
        is False
    )

    conflicting_release_metadata = write_packet(
        tmp_path / "conflicting-release-metadata",
        release_metadata_extra=("git_commit=" + "b" * 40, "git_dirty=true"),
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(
            conflicting_release_metadata,
            commit,
        )
        is False
    )

    trailing_release_output = write_packet(
        tmp_path / "trailing-release-output",
        release_trailing_output=("not part of a successful release footer",),
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(
            trailing_release_output,
            commit,
        )
        is False
    )

    conflicting_summary = write_packet(
        tmp_path / "conflicting-summary",
        git_summary_extra=("commit=" + "b" * 40, "dirty=true"),
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(
            conflicting_summary,
            commit,
        )
        is False
    )

    unlisted = write_packet(tmp_path / "unlisted")
    unlisted.joinpath("unlisted.txt").write_text(
        "bounded but absent from the manifest\n",
        encoding="utf-8",
    )
    assert enterprise_current_checkpoint._immutable_packet_valid(unlisted, commit) is False

    forbidden = write_packet(tmp_path / "forbidden")
    forbidden.joinpath(".env").write_text(
        "ITHILDIN_ADMIN_TOKEN=not-allowed\n",
        encoding="utf-8",
    )
    assert enterprise_current_checkpoint._immutable_packet_valid(forbidden, commit) is False

    duplicate = write_packet(tmp_path / "duplicate")
    duplicate_manifest = json.loads(
        duplicate.joinpath("artifact-hashes.json").read_text(encoding="utf-8")
    )
    duplicate_manifest.append(duplicate_manifest[0])
    duplicate.joinpath("artifact-hashes.json").write_text(
        json.dumps(duplicate_manifest),
        encoding="utf-8",
    )
    assert enterprise_current_checkpoint._immutable_packet_valid(duplicate, commit) is False

    symlinked_ancestor = write_packet(
        tmp_path / "symlinked-ancestor",
        nested_payload=True,
    )
    external = tmp_path / "external"
    external.mkdir()
    external.joinpath("payload.txt").write_text("bounded evidence\n", encoding="utf-8")
    symlinked_ancestor.joinpath("nested/payload.txt").unlink()
    symlinked_ancestor.joinpath("nested").rmdir()
    symlinked_ancestor.joinpath("nested").symlink_to(
        external,
        target_is_directory=True,
    )
    assert (
        enterprise_current_checkpoint._immutable_packet_valid(
            symlinked_ancestor,
            commit,
        )
        is False
    )


def test_enterprise_current_checkpoint_accepts_packet_blocked_prose(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.setattr(
        mission_command_control_plane_poc_evidence_check,
        "build_report",
        lambda _repo_root: {"valid": True, "failures": [], "tool_count": 24},
    )

    cached_defaults = enterprise_current_checkpoint.build_report.__kwdefaults__
    assert cached_defaults is not None
    original_build_report = cached_defaults["_original"]
    report = original_build_report(Path.cwd())

    assert report["valid"] is True, report
    assert report["review_candidate_prerequisite_mcc_006_valid"] is True
    assert report["immutable_review_packet_valid"] is False
    assert report["review_candidate_blocker"] == (
        "missing_or_invalid_immutable_review_packet"
    )
    assert report["failures"] == []


def test_enterprise_current_checkpoint_rejects_mcc_blocked_prose_after_live_evidence(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.setattr(
        mission_command_control_plane_poc_evidence_check,
        "build_report",
        lambda _repo_root: {"valid": True, "failures": [], "tool_count": 24},
    )
    original_read = enterprise_current_checkpoint._read

    def read_with_stale_mcc_prose(path: Path) -> str:
        document = original_read(path)
        if path.name == "enterprise-current-checkpoint.md":
            return (
                document
                + "\n"
                + enterprise_current_checkpoint.MCC_BLOCKED_PHRASES[0]
                + "\n"
            )
        return document

    monkeypatch.setattr(enterprise_current_checkpoint, "_read", read_with_stale_mcc_prose)
    cached_defaults = enterprise_current_checkpoint.build_report.__kwdefaults__
    assert cached_defaults is not None
    original_build_report = cached_defaults["_original"]

    report = original_build_report(Path.cwd())

    assert report["valid"] is False
    assert report["review_candidate_prerequisite_mcc_006_valid"] is True
    assert report["review_candidate_blocker"] == "missing_or_invalid_immutable_review_packet"
    assert any(
        enterprise_current_checkpoint.MCC_BLOCKED_PHRASES[0] in failure
        and "contradicts computed packet state" in failure
        for failure in report["failures"]
    )


