        sandbox_vm_live_poc_runtime_descriptor_only_response_inbox.SandboxVmLivePocRuntimeDescriptorOnlyResponseInboxError,
        match="05_ERG004_DESCRIPTOR_ONLY_COMMAND_EVIDENCE.md",
