def test_review_candidate_target_sequences_handoff_commands() -> None:
    makefile = Path("Makefile").read_text(encoding="utf-8")
    target = re.search(r"^review-candidate:\n(?P<body>(?:\t.*\n)+)", makefile, re.MULTILINE)

    assert target is not None
    body = target.group("body")
    expected_commands = [
        "$(MAKE) review-candidate-release-transcript",
        "$(MAKE) filesystem-contract-check",
        "$(MAKE) signed-evidence-demo",
        "$(MAKE) signed-evidence-demo-verify",
        "$(MAKE) negative-review-transcripts",
        "$(MAKE) operator-sandbox-demo-packet",
        "$(MAKE) agent-run-correlation-packet",
        "$(MAKE) live-demo-status",
        "$(MAKE) live-demo-smoke",
        "$(MAKE) live-demo-evidence-summary",
        "$(MAKE) live-demo-packet",
        "$(MAKE) v06-review-dispatch-packets",
        "scripts/review_packet_bundle.py --release-check-transcript",
        "$(MAKE) review-packet-consolidated",
        "$(MAKE) packet-redaction-scan",
        "$(MAKE) docs-site",
    ]
    positions = [body.index(command) for command in expected_commands]
    assert positions == sorted(positions)
    transcript_target = re.search(
        r"^review-candidate-release-transcript:\n(?P<body>(?:\t.*\n)+)",
        makefile,
        re.MULTILINE,
    )
    assert transcript_target is not None
    assert "$(MAKE) release-check" in transcript_target.group("body")
    assert "review-candidate-release-check.txt" in body
    assert "v1.0 RC packet ready: var/review-packets/v1.0/rc" in body
    assert (
        "Historical consolidated packet ready: "
        "var/review-packets/v0.2/GPT-5.5-Pro-consolidated"
    ) in body
    assert "Review candidate ready: var/review-packets/v0.2/GPT-5.5-Pro-consolidated" not in body


